package com.DAO; import java.sql.*; import java.util.*; import com.entity.Book_Order;
public class BookOrderImpl implements BookOrderDAO { private final Connection conn; public BookOrderImpl(Connection c){conn=c;}
 public boolean saveOrder(List<Book_Order> list){String q="INSERT INTO book_order(order_id,user_name,email,address,phone,book_name,author,price,payment) VALUES(?,?,?,?,?,?,?,?,?)";try{conn.setAutoCommit(false);try(PreparedStatement p=conn.prepareStatement(q)){for(Book_Order o:list){p.setString(1,o.getOrderId());p.setString(2,o.getUserName());p.setString(3,o.getEmail());p.setString(4,o.getFulladd());p.setString(5,o.getPhno());p.setString(6,o.getBookName());p.setString(7,o.getAuthor());p.setString(8,o.getPrice());p.setString(9,o.getPaymentType());p.addBatch();}p.executeBatch();}conn.commit();return true;}catch(SQLException e){try{conn.rollback();}catch(Exception ignored){}e.printStackTrace();return false;}finally{try{conn.setAutoCommit(true);}catch(Exception ignored){}}}
 public List<Book_Order> getBook(String email){return query("SELECT * FROM book_order WHERE email=? ORDER BY id DESC",email);} public List<Book_Order> getAllOrder(){return query("SELECT * FROM book_order ORDER BY id DESC",null);}
 private List<Book_Order> query(String q,String email){List<Book_Order>a=new ArrayList<>();try(PreparedStatement p=conn.prepareStatement(q)){if(email!=null)p.setString(1,email);try(ResultSet r=p.executeQuery()){while(r.next()){Book_Order o=new Book_Order();o.setId(r.getInt("id"));o.setOrderId(r.getString("order_id"));o.setUserName(r.getString("user_name"));o.setEmail(r.getString("email"));o.setFulladd(r.getString("address"));o.setPhno(r.getString("phone"));o.setBookName(r.getString("book_name"));o.setAuthor(r.getString("author"));o.setPrice(r.getString("price"));o.setPaymentType(r.getString("payment"));a.add(o);}}}catch(SQLException e){e.printStackTrace();}return a;}
}
